import { useEffect, useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { Button } from '@/components/ui/button';
import {
    Facebook,
    RefreshCw,
    Check,
    XCircle,
    AlertTriangle,
    Loader2,
    Link2,
    Unlink,
    Globe,
    ExternalLink,
    ShieldCheck,
    Zap
} from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { motion, AnimatePresence } from 'framer-motion';

interface Integration {
    id: string;
    company_id: string;
    platform: string;
    account_id: string;
    account_name: string;
    status: string;
    last_sync_at: string | null;
    token_expires_at: string | null;
    created_at: string;
}

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.1
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0 }
};

export default function Integracoes() {
    const { user } = useAuth();
    const { toast } = useToast();
    const [integrations, setIntegrations] = useState<Integration[]>([]);
    const [loading, setLoading] = useState(true);
    const [syncing, setSyncing] = useState<string | null>(null);
    const [connecting, setConnecting] = useState(false);

    useEffect(() => {
        fetchIntegrations();

        const params = new URLSearchParams(window.location.search);
        if (params.get('success') === 'true') {
            const accounts = params.get('accounts');
            toast({
                title: 'Conexão realizada!',
                description: `${accounts} conta(s) de anúncios conectada(s) com sucesso.`,
            });
            window.history.replaceState({}, '', '/integracoes');
            fetchIntegrations();
        }
    }, []);

    const fetchIntegrations = async () => {
        if (!user?.company?.id) return;

        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('integrations')
                .select('*')
                .eq('company_id', user.company.id)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setIntegrations(data || []);
        } catch (error) {
            console.error('Error fetching integrations:', error);
            toast({
                title: 'Erro',
                description: 'Não foi possível carregar as integrações.',
                variant: 'destructive',
            });
        } finally {
            setLoading(false);
        }
    };

    const handleConnectMeta = () => {
        if (!user?.company?.id || !user?.id) {
            toast({
                title: 'Erro',
                description: 'Dados do usuário não encontrados.',
                variant: 'destructive',
            });
            return;
        }

        setConnecting(true);
        const META_APP_ID = import.meta.env.VITE_META_APP_ID;
        const SUPABASE_URL = supabaseUrl;

        if (!META_APP_ID) {
            toast({
                title: 'Erro de configuração',
                description: 'META_APP_ID não configurado.',
                variant: 'destructive',
            });
            setConnecting(false);
            return;
        }

        const state = btoa(JSON.stringify({
            user_id: user.id,
            company_id: user.company.id,
            redirect_url: window.location.origin + '/integracoes'
        }));

        const redirectUri = `${SUPABASE_URL}/functions/v1/meta-oauth-callback`;
        const scopes = 'ads_read,ads_management,business_management,pages_read_engagement,read_insights';
        const oauthUrl = `https://www.facebook.com/v19.0/dialog/oauth?client_id=${META_APP_ID}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${scopes}&state=${state}&response_type=code`;
        window.location.href = oauthUrl;
    };

    const handleSync = async (integrationId: string) => {
        setSyncing(integrationId);
        try {
            const { data, error } = await supabase.functions.invoke('sync-meta-data', {
                body: { integration_id: integrationId, sync_type: 'full' }
            });

            if (error) throw error;

            toast({
                title: 'Sincronização concluída',
                description: `${data.results?.[0]?.items_synced || 0} itens sincronizados.`,
            });

            fetchIntegrations();
        } catch (error) {
            console.error('Sync error:', error);
            toast({
                title: 'Erro na sincronização',
                description: 'Não foi possível sincronizar os dados.',
                variant: 'destructive',
            });
        } finally {
            setSyncing(null);
        }
    };

    const handleDisconnect = async (integrationId: string) => {
        if (!confirm('Tem certeza que deseja desconectar esta conta?')) return;

        try {
            const { error } = await supabase
                .from('integrations')
                .update({ status: 'disconnected' })
                .eq('id', integrationId);

            if (error) throw error;

            toast({
                title: 'Conta desconectada',
                description: 'A integração foi removida com sucesso.',
            });

            fetchIntegrations();
        } catch (error) {
            console.error('Disconnect error:', error);
            toast({
                title: 'Erro',
                description: 'Não foi possível desconectar a conta.',
                variant: 'destructive',
            });
        }
    };

    const getStatusBadge = (integration: Integration) => {
        const isExpired = integration.token_expires_at &&
            new Date(integration.token_expires_at) < new Date();

        if (isExpired) {
            return (
                <span className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full bg-amber-500/10 text-amber-500 border border-amber-500/20">
                    <AlertTriangle className="w-3.5 h-3.5" />
                    Token expirado
                </span>
            );
        }

        if (integration.status === 'active') {
            return (
                <span className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full bg-emerald-500/10 text-emerald-500 border border-emerald-500/20">
                    <Check className="w-3.5 h-3.5" />
                    Ativo
                </span>
            );
        }

        return (
            <span className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full bg-rose-500/10 text-rose-500 border border-rose-500/20">
                <XCircle className="w-3.5 h-3.5" />
                Inativo
            </span>
        );
    };

    const metaIntegrations = integrations.filter(i => i.platform === 'meta' && i.status !== 'disconnected');

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            {/* Header */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <Globe className="w-5 h-5 text-ch-orange animate-pulse" />
                        <span className="text-xs font-black text-ch-orange uppercase tracking-[0.2em]">Centro de Conexões</span>
                    </div>
                    <h1 className="text-4xl font-black text-ch-white tracking-tight italic uppercase">Integrações</h1>
                    <p className="text-ch-text-dimmed font-medium mt-1">
                        Conecte seu ecossistema de anúncios para ativar a inteligência <span className="text-ch-white font-bold">Click.Hero</span>
                    </p>
                </div>
                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/5 border border-emerald-500/10 rounded-xl">
                        <ShieldCheck className="w-4 h-4 text-emerald-500" />
                        <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Ambiente Seguro</span>
                    </div>
                </div>
            </motion.div>

            {/* Platform Connect Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <motion.div variants={item} className="lg:col-span-2 glass-premium rounded-3xl p-8 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-12 opacity-[0.03] group-hover:opacity-[0.08] transition-all duration-500 pointer-events-none">
                        <Facebook className="w-64 h-64" />
                    </div>
                    <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-8 relative z-10">
                        <div className="flex items-center gap-6">
                            <div className="p-5 bg-blue-600 rounded-3xl shadow-2xl shadow-blue-600/20 group-hover:scale-110 transition-transform">
                                <Facebook className="w-10 h-10 text-white" />
                            </div>
                            <div>
                                <h2 className="text-2xl font-black text-ch-white tracking-tight uppercase">Facebook & Meta Ads</h2>
                                <p className="text-ch-text-dimmed font-medium mt-1 max-w-md">
                                    Sincronize campanhas, conjuntos de anúncios e criativos do Meta Business Suite em tempo real.
                                </p>
                            </div>
                        </div>
                        <Button
                            onClick={handleConnectMeta}
                            disabled={connecting}
                            className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-2xl h-14 px-8 transition-all group/btn shadow-xl"
                        >
                            {connecting ? (
                                <Loader2 className="w-5 h-5 mr-3 animate-spin" />
                            ) : (
                                <Zap className="w-5 h-5 mr-3 group-hover:animate-bounce" />
                            )}
                            {metaIntegrations.length > 0 ? 'Adicionar Canal' : 'Ativar Integração'}
                        </Button>
                    </div>
                    <div className="mt-8 pt-6 border-t border-white/5 flex gap-6 italic text-[10px] font-bold text-ch-text-muted uppercase tracking-widest">
                        <span className="flex items-center gap-1.5"><ExternalLink className="w-3 h-3" /> OAuth 2.0</span>
                        <span className="flex items-center gap-1.5"><ShieldCheck className="w-3 h-3" /> Criptografia Ponta a Ponta</span>
                    </div>
                </motion.div>

                <motion.div variants={item} className="glass rounded-3xl p-8 border-white/5 bg-white/[0.02] flex flex-col justify-center text-center">
                    <h3 className="font-black text-ch-white uppercase tracking-tighter mb-2">Próximos Canais</h3>
                    <p className="text-xs text-ch-text-dimmed font-medium mb-6">Estamos trabalhando para integrar novas plataformas em breve.</p>
                    <div className="grid grid-cols-2 gap-3 opacity-30 grayscale pointer-events-none">
                        {/* <div className="p-4 bg-white/5 rounded-2xl border border-white/5 flex flex-col items-center gap-2">
                            <div className="w-8 h-8 rounded-full bg-rose-500/20" />
                            <span className="text-[10px] font-bold">Google Ads</span>
                        </div> */}
                        <div className="p-4 bg-white/5 rounded-2xl border border-white/5 flex flex-col items-center gap-2">
                            <div className="w-8 h-8 rounded-full bg-teal-500/20" />
                            <span className="text-[10px] font-bold">TikTok Ads</span>
                        </div>
                    </div>
                </motion.div>
            </div>

            {/* Connected Accounts Section */}
            <div className="space-y-6">
                <motion.div variants={item} className="flex items-center gap-3 ml-1">
                    <Link2 className="w-5 h-5 text-ch-orange" />
                    <h2 className="text-xl font-black text-ch-white uppercase tracking-wider">Canais Conectados</h2>
                    {metaIntegrations.length > 0 && (
                        <span className="bg-ch-orange/10 text-ch-orange text-[10px] font-black px-2 py-0.5 rounded-full border border-ch-orange/20">
                            {metaIntegrations.length}
                        </span>
                    )}
                </motion.div>

                {loading ? (
                    <div className="glass rounded-3xl p-20 flex flex-col items-center justify-center gap-4">
                        <Loader2 className="w-10 h-10 animate-spin text-ch-orange opacity-40" />
                        <p className="text-ch-text-dimmed font-black uppercase text-xs tracking-widest">Varrendo infraestrutura...</p>
                    </div>
                ) : metaIntegrations.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        <AnimatePresence>
                            {metaIntegrations.map((integration) => (
                                <motion.div
                                    key={integration.id}
                                    variants={item}
                                    layout
                                    exit={{ opacity: 0, scale: 0.9 }}
                                    className="glass-card rounded-2xl p-6 relative group overflow-hidden"
                                >
                                    <div className="flex items-start justify-between relative z-10">
                                        <div className="flex items-center gap-4">
                                            <div className="p-3 bg-blue-600/10 rounded-2xl border border-blue-600/20 group-hover:bg-blue-600 transition-all duration-500">
                                                <Facebook className="w-5 h-5 text-blue-500 group-hover:text-white" />
                                            </div>
                                            <div>
                                                <p className="font-black text-ch-white uppercase tracking-tight group-hover:text-ch-orange transition-colors">
                                                    {integration.account_name || `Conta Meta`}
                                                </p>
                                                <p className="text-[10px] font-black text-ch-text-dimmed tracking-widest uppercase mt-1">
                                                    ID: {integration.account_id}
                                                </p>
                                            </div>
                                        </div>
                                        {getStatusBadge(integration)}
                                    </div>

                                    <div className="mt-8 space-y-4 relative z-10">
                                        {integration.last_sync_at && (
                                            <div className="flex items-center justify-between p-3 bg-white/[0.02] rounded-xl border border-white/5">
                                                <span className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest flex items-center gap-1.5">
                                                    <RefreshCw className="w-3 h-3" /> Última Sync
                                                </span>
                                                <span className="text-[10px] font-black text-ch-white tabular-nums">
                                                    {format(new Date(integration.last_sync_at), "dd/MM/yyyy HH:mm", { locale: ptBR })}
                                                </span>
                                            </div>
                                        )}

                                        <div className="flex items-center gap-2 pt-2">
                                            <Button
                                                variant="outline"
                                                className="flex-1 bg-ch-dark-gray/40 border-white/5 hover:border-ch-orange/30 hover:bg-ch-orange/10 hover:text-ch-orange font-black uppercase text-[10px] tracking-widest h-11 rounded-xl transition-all"
                                                onClick={() => handleSync(integration.id)}
                                                disabled={syncing === integration.id}
                                            >
                                                {syncing === integration.id ? (
                                                    <Loader2 className="w-4 h-4 animate-spin" />
                                                ) : (
                                                    <RefreshCw className="w-4 h-4 mr-2" />
                                                )}
                                                Sincronizar
                                            </Button>

                                            <Button
                                                variant="ghost"
                                                className="w-11 h-11 p-0 rounded-xl bg-rose-500/5 hover:bg-rose-500/10 text-rose-500 hover:text-rose-400 border border-transparent hover:border-rose-500/20 transition-all"
                                                onClick={() => handleDisconnect(integration.id)}
                                            >
                                                <Unlink className="w-4 h-4" />
                                            </Button>
                                        </div>
                                    </div>

                                    {/* Subtle decorative background element */}
                                    <div className="absolute -bottom-4 -right-4 w-24 h-24 bg-blue-600/5 blur-3xl rounded-full group-hover:bg-blue-600/10 transition-colors" />
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </div>
                ) : (
                    <motion.div
                        variants={item}
                        className="glass rounded-3xl p-16 text-center border-white/5 bg-white/[0.01]"
                    >
                        <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-8 animate-pulse">
                            <Link2 className="w-10 h-10 text-ch-text-muted opacity-30" />
                        </div>
                        <h3 className="text-xl font-black text-ch-white uppercase tracking-tighter mb-3">Expansão Necessária</h3>
                        <p className="text-ch-text-muted font-medium max-w-md mx-auto mb-8">
                            Ainda não detectamos conexões ativas. Ative sua conta Meta Ads para que a IA possa extrair inteligência das suas campanhas.
                        </p>
                        <Button
                            onClick={handleConnectMeta}
                            className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest px-8 h-12 rounded-xl transition-all"
                        >
                            Começar Agora
                        </Button>
                    </motion.div>
                )}
            </div>
        </motion.div>
    );
}
